// ── Configurações ─────────────────────────────────────────
const workflow = $json;
const config   = $('Configurações').first().json;

// ── Gera base64 do conteúdo ───────────────────────────────
const content = JSON.stringify(workflow, null, 2);
const base64  = Buffer.from(content).toString('base64');

// ── Determina pasta ───────────────────────────────────────
let folderPath = '_sem_pasta';
if (workflow.parentFolder && workflow.parentFolder.name) {
  folderPath = workflow.parentFolder.name;
} else if (workflow.folder && workflow.folder.name) {
  folderPath = workflow.folder.name;
} else if (workflow.tags && workflow.tags.length > 0) {
  folderPath = workflow.tags[0].name;
}

const sanitize = (s) => String(s)
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-zA-Z0-9\-_\s]/g, '')
  .trim()
  .replace(/\s+/g, '_');

const filePath = `workflows/${sanitize(folderPath)}/${sanitize(workflow.name)}.json`;

const headers = {
  'Authorization'       : config.githubToken,
  'Accept'              : 'application/vnd.github+json',
  'X-GitHub-Api-Version': '2022-11-28',
  'Content-Type'        : 'application/json'
};

const url = `https://api.github.com/repos/${config.githubOwner}/${config.githubRepo}/contents/${filePath}`;

// ── Busca SHA atual ───────────────────────────────────────
const getSha = async () => {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url,
      headers,
      returnFullResponse: true,
      ignoreHttpStatusErrors: true
    });
    if (resp.statusCode === 200 && resp.body && resp.body.sha) {
      return resp.body.sha;
    }
  } catch (e) {}
  return null;
};

// ── PUT com retry no 409 ──────────────────────────────────
const salvar = async (sha, tentativa) => {
  const payload = {
    message: `chore: backup "${workflow.name}"`,
    content : base64,
    branch  : config.githubBranch
  };
  if (sha) payload.sha = sha;

  const resp = await this.helpers.httpRequest({
    method: 'PUT',
    url,
    headers,
    body: payload,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  });

  if (resp.statusCode === 409 && tentativa < 3) {
    await new Promise(r => setTimeout(r, 1000 * tentativa));
    const novoSha = await getSha();
    return salvar(novoSha, tentativa + 1);
  }

  return { resp, sha };
};

// ── Executa ───────────────────────────────────────────────
const shaInicial = await getSha();
const { resp } = await salvar(shaInicial, 1);

if (resp.statusCode !== 200 && resp.statusCode !== 201) {
  throw new Error(`GitHub ${resp.statusCode}: ${JSON.stringify(resp.body)}`);
}

return [{
  json: {
    workflowName : workflow.name,
    filePath,
    acao         : shaInicial ? 'ATUALIZADO' : 'CRIADO',
    httpStatus   : resp.statusCode,
    shaAnterior  : shaInicial || null,
    commitSha    : resp.body && resp.body.commit ? resp.body.commit.sha : null
  }
}];

const itens = $json.data || [];

const erros    = itens.filter(i => i.error || (i.httpStatus && i.httpStatus >= 400));
const criados  = itens.filter(i => i.acao === 'CRIADO');
const atualizados = itens.filter(i => i.acao === 'ATUALIZADO');

console.log('✅ Criados:', criados.length);
console.log('🔄 Atualizados:', atualizados.length);
console.log('❌ Erros:', erros.length, JSON.stringify(erros, null, 2));

return [{ json: { criados: criados.length, atualizados: atualizados.length, erros } }];
